window.PACTO.acts["reg-2011-1077"]={"label": "REGOLAMENTO (UE) N. 1077/2011 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 1077/2011", "file": "ext-reg-2011-1077.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/reg/2011/1077/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Istituzione dell’agenzia", "anchor": "art_1", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   È istituita un’agenzia europea per la gestione operativa di sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia («l’agenzia»).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’agenzia è responsabile della gestione operativa del sistema d’informazione Schengen di seconda generazione (SIS II), del sistema d’informazione visti (VIS) e di Eurodac.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’agenzia può inoltre essere incaricata della preparazione, dello sviluppo e della gestione operativa di sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia diversi da quelli di cui al paragrafo 2, solo se così previsto dai pertinenti strumenti legislativi sulla base degli articoli da 67 a 89 TFUE, tenendo conto, ove opportuno, degli sviluppi della ricerca di cui all’articolo 8 del presente regolamento e dei risultati dei progetti pilota di cui all’articolo 9 del presente regolamento.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La gestione operativa comprende tutti i compiti necessari per mantenere operativi i sistemi IT su larga scala, conformemente alle disposizioni specifiche applicabili a ciascuno di loro, inclusa la responsabilità per l’infrastruttura di comunicazione da essi utilizzata. Tali sistemi IT su larga scala non si scambiano dati o non consentono la condivisione di informazioni o di conoscenze, salvo se così previsto da una specifica base giuridica.</p>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Obiettivi", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Fatte salve le rispettive responsabilità della Commissione e degli Stati membri ai sensi degli strumenti legislativi che disciplinano i sistemi IT su larga scala, l’agenzia garantisce:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un esercizio efficace, sicuro e continuo dei sistemi IT su larga scala;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la gestione efficiente e finanziariamente responsabile dei sistemi IT su larga scala;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un servizio di qualità adeguatamente elevata per gli utenti dei sistemi IT su larga scala;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">continuità e un servizio ininterrotto;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un livello elevato di protezione dei dati, conformemente alle norme applicabili, comprese le disposizioni specifiche per ciascun sistema IT su larga scala;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un livello adeguato di sicurezza dei dati e materiale, in conformità delle norme applicabili, comprese le disposizioni specifiche relative a ciascun sistema IT su larga scala; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’utilizzazione di un’adeguata struttura di gestione di progetto per lo sviluppo efficiente di sistemi IT su larga scala.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "3": {"label": "Articolo 3", "heading": "Compiti relativi al SIS II", "anchor": "art_3", "frags": [[null, "<p class=\"oj-normal\">Con riguardo al SIS II, l’agenzia svolge:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti che il regolamento (CE) n. 1987/2006 e la decisione 2007/533/GAI attribuiscono all’autorità di gestione; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti relativi alla formazione sull’uso tecnico del SIS II, destinata in particolare per il personale SIRENE (SIRENE — informazioni supplementari richieste agli ingressi nazionali), nonché alla formazione di esperti sugli aspetti tecnici del SIS II nel quadro della valutazione di Schengen.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "4": {"label": "Articolo 4", "heading": "Compiti relativi al VIS", "anchor": "art_4", "frags": [[null, "<p class=\"oj-normal\">Con riguardo al VIS, l’agenzia svolge:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti che il regolamento (CE) n. 767/2008 e la decisione 2008/633/GAI attribuiscono all’organo di gestione; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti relativi alla formazione sull’uso tecnico del VIS.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "5": {"label": "Articolo 5", "heading": "Compiti relativi a Eurodac", "anchor": "art_5", "frags": [[null, "<p class=\"oj-normal\">Con riguardo a Eurodac, l’agenzia svolge:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti attribuiti alla Commissione in qualità di autorità responsabile della gestione operativa di Eurodac conformemente ai regolamenti (CE) n. 2725/2000 e (CE) n. 407/2002;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti relativi all’infrastruttura di comunicazione, in particolare la supervisione, la sicurezza e il coordinamento delle relazioni tra gli Stati membri e il fornitore; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti relativi alla formazione sull’uso tecnico di Eurodac.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "6": {"label": "Articolo 6", "heading": "Compiti relativi allo sviluppo e alla gestione operativa di altri sistemi IT su larga scala", "anchor": "art_6", "frags": [[null, "<p class=\"oj-normal\">Ove sia incaricata della preparazione, dello sviluppo e della gestione operativa di altri sistemi IT su larga scala di cui all’articolo 1, paragrafo 3, l’agenzia svolge, se del caso, compiti relativi alla formazione sull’uso tecnico di tali sistemi.</p>"]]}, "7": {"label": "Articolo 7", "heading": "Compiti relativi all’infrastruttura di comunicazione", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’agenzia svolge i compiti relativi all’infrastruttura di comunicazione attribuiti all’organo di gestione dagli strumenti legislativi che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso dei sistemi IT su larga scala di cui all’articolo 1, paragrafo 2.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Conformemente agli strumenti legislativi di cui al paragrafo 1, i compiti relativi all’infrastruttura di comunicazione (compresi la gestione operativa e la sicurezza) sono suddivisi tra l’agenzia e la Commissione. Per assicurare la coerenza tra l’esercizio delle loro rispettive responsabilità, tra l’agenzia e la Commissione sono conclusi accordi di lavoro operativi, rispecchiati in un memorandum d’intesa.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’infrastruttura di comunicazione è adeguatamente gestita e controllata al fine di proteggerla da minacce e di garantire la sua sicurezza e quella dei sistemi IT su larga scala, compresa la sicurezza dei dati scambiati attraverso l’infrastruttura di comunicazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Sono adottate misure adeguate comprendenti piani di sicurezza volti tra l’altro ad impedire, in particolare mediante tecniche appropriate di cifratura, che durante la trasmissione di dati personali o il trasporto dei supporti di dati, tali dati personali possano essere letti, copiati, modificati o cancellati senza autorizzazione. Nessuna informazione operativa connessa al sistema circola senza cifratura nell’infrastruttura di comunicazione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I compiti relativi alla gestione operativa dell’infrastruttura di comunicazione possono essere affidati a soggetti o ad organismi esterni di diritto privato conformemente al regolamento (CE, Euratom) n. 1605/2002. In tal caso, il gestore della rete è vincolato dalle misure di sicurezza di cui al paragrafo 4 e non ha accesso in alcun modo ai dati operativi SIS II, VIS o Eurodac o agli scambi SIRENE relativi al SIS II.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Fatti salvi i contratti esistenti sulla rete di SIS II, VIS e Eurodac la gestione delle chiavi criptate rimane di competenza dell’agenzia e non è esternalizzata ad alcun soggetto esterno di diritto privato.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Monitoraggio della ricerca", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’agenzia segue gli sviluppi della ricerca per la gestione operativa del SIS II, del VIS, di Eurodac e di altri sistemi IT su larga scala.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’agenzia riferisce periodicamente al Parlamento europeo, al Consiglio, alla Commissione e, per le questioni relative alla protezione dei dati, al garante europeo della protezione dei dati circa gli sviluppi di cui al paragrafo 1.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Progetti pilota", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Soltanto su richiesta esplicita e circostanziata della Commissione, che ne ha informato il Parlamento europeo e il Consiglio con almeno tre mesi di anticipo, e in seguito a una decisione del consiglio di amministrazione, l’agenzia, in conformità dell’articolo 12, paragrafo 1, lettera l), può realizzare progetti pilota di cui all’articolo 49, paragrafo 6, lettera a), del regolamento (CE, Euratom) n. 1605/2002, per lo sviluppo e/o la gestione operativa di sistemi IT su larga scala, in applicazione degli articoli da 67 a 89 TFUE.</p>\n<p class=\"oj-normal\">L’agenzia informa regolarmente il Parlamento europeo, il Consiglio e, per le questioni relative alla protezione dei dati, il garante europeo della protezione dei dati dell’evoluzione dei progetti pilota di cui al primo comma.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli stanziamenti per i progetti pilota richiesti dalla Commissione sono iscritti in bilancio per non più di due esercizi successivi.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Natura giuridica", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’agenzia è un organismo dell’Unione ed è dotata di personalità giuridica.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’agenzia gode, in tutti gli Stati membri, della più ampia capacità giuridica riconosciuta alle persone giuridiche dalla legislazione nazionale. In particolare, essa può acquistare o alienare beni mobili e immobili e può stare in giudizio L’agenzia può anche concludere accordi sulla sua sede e sui siti istituiti conformemente al paragrafo 4 con gli Stati membri sui cui territori sono situati la sede e i siti tecnici e di riserva («Stati membri ospitanti»).</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’agenzia è rappresentata dal proprio direttore esecutivo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’agenzia ha sede a Tallinn, Estonia.</p>\n<p class=\"oj-normal\">I compiti relativi allo sviluppo e alla gestione operativa di cui all’articolo 1, paragrafo 3, agli articoli 3, 4, 5 e 7 sono svolti a Strasburgo, Francia.</p>\n<p class=\"oj-normal\">Un sito di riserva in grado di assicurare il funzionamento di un sistema IT su larga scala in caso di guasto di tale sistema è installato a Sankt Johann im Pongau, Austria, se lo strumento legislativo che ne disciplina lo sviluppo, l’istituzione, l’esercizio e l’uso prevede un sito di riserva.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Struttura", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La struttura amministrativa e di gestione dell’agenzia è composta da:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un direttore esecutivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gruppi consultivi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La struttura dell’agenzia comprende altresì:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un responsabile della protezione dei dati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un responsabile della sicurezza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contabile.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Funzioni del consiglio di amministrazione", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per permettere all’agenzia di svolgere i suoi compiti, il consiglio di amministrazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina e, se necessario, revoca il direttore esecutivo conformemente all’articolo 18;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esercita l’autorità disciplinare nei confronti del direttore esecutivo e ne controlla l’operato, compresa l’esecuzione delle decisioni del consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce la struttura organizzativa dell’agenzia previa consultazione della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce il regolamento interno dell’agenzia previa consultazione della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">approva, su proposta del direttore esecutivo, gli accordi sulla sede relativi alla sede dell’agenzia e gli accordi relativi ai siti tecnici e di riserva in conformità dell’articolo 10, paragrafo 4, che il direttore esecutivo deve firmare con gli Stati membri ospitanti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta, di concerto con la Commissione, le necessarie disposizioni di esecuzione di cui all’articolo 110 dello statuto dei funzionari;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta le necessarie disposizioni di esecuzione relative al distacco di esperti nazionali presso l’agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta un programma di lavoro pluriennale basato sui compiti di cui al capo II, partendo da un progetto presentato dal direttore esecutivo di cui all’articolo 17, previa consultazione dei gruppi consultivi di cui all’articolo 19 e previa ricezione del parere della Commissione. Fatta salva la procedura annuale di bilancio, il programma di lavoro pluriennale comprende una stima di bilancio pluriennale e valutazioni ex ante volte a strutturare gli obiettivi e le diverse fasi della pianificazione pluriennale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta un piano pluriennale in materia di politica del personale e un progetto di programma di lavoro annuale e li presenta entro il 31 marzo di ogni anno alla Commissione e all’autorità di bilancio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta, entro il 30 settembre di ogni anno, e sentito il parere della Commissione, a maggioranza dei due terzi dei membri aventi diritto di voto, e conformemente alla procedura annuale di bilancio e al programma legislativo dell’Unione nei settori disciplinati dagli articoli da 67 a 89 TFUE, il programma di lavoro annuale dell’agenzia per l’anno successivo; provvede inoltre affinché il programma di lavoro adottato sia trasmesso al Parlamento europeo, al Consiglio e alla Commissione e sia pubblicato;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta, entro il 31 marzo di ogni anno, la relazione annuale di attività dell’agenzia per l’anno precedente confrontando, in particolare, i risultati ottenuti con gli obiettivi del programma di lavoro annuale e entro il 15 giugno dello stesso anno la trasmette al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti; la relazione annuale di attività è pubblicata;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">svolge le sue funzioni riguardanti il bilancio dell’agenzia, compresa l’attuazione dei progetti pilota di cui all’articolo 9, conformemente all’articolo 32, all’articolo 33, paragrafo 6, e all’articolo 34;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta le norme finanziarie applicabili all’agenzia ai sensi dell’articolo 34;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina un contabile, che è funzionalmente indipendente nell’espletamento dei suoi compiti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assicura un seguito adeguato alle conclusioni e alle raccomandazioni derivanti dalle varie relazioni di revisione contabile e valutazioni, sia interne che esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta le misure di sicurezza necessarie, compresi un piano di sicurezza ed un piano di continuità operativa e di ripristino in caso di disastro, tenendo conto delle eventuali raccomandazioni degli esperti della sicurezza che fanno parte dei gruppi consultivi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina un responsabile della sicurezza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina un responsabile della protezione dei dati conformemente al regolamento (CE) n. 45/2001;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta entro il 22 maggio 2012 le modalità pratiche di applicazione del regolamento (CE) n. 1049/2001;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">t)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta le relazioni sul funzionamento tecnico del SIS II in conformità, rispettivamente, dell’articolo 50, paragrafo 4, del regolamento (CE) n. 1987/2006 e dell’articolo 66, paragrafo 4, della decisione 2007/533/GAI e del VIS in conformità dell’articolo 50, paragrafo 3, del regolamento (CE) n. 767/2008 e dell’articolo 17, paragrafo 3, della decisione 2008/633/GAI;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">u)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta la relazione annuale sulle attività dell’unità centrale di Eurodac conformemente all’articolo 24, paragrafo 1, del regolamento (CE) n. 2725/2000;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">v)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presenta osservazioni sulle relazioni del garante europeo della protezione dei dati relative ai controlli conformemente all’articolo 45 del regolamento (CE) n. 1987/2006 e all’articolo 42, paragrafo 2, del regolamento (CE) n. 767/2008 e assicura adeguato seguito ai controlli;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">w)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">pubblica le statistiche relative al SIS II in conformità, rispettivamente, dell’articolo 50, paragrafo 3, del regolamento (CE) n. 1987/2006 e dell’articolo 66, paragrafo 3, della decisione 2007/533/GAI;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">x)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">elabora statistiche sulle attività dell’unità centrale di Eurodac conformemente all’articolo 3, paragrafo 3, del regolamento (CE) n. 2725/2000;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">y)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvede alla pubblicazione annuale dell’elenco delle autorità competenti autorizzate a consultare direttamente i dati inseriti nel SIS II in conformità dell’articolo 31, paragrafo 8, del regolamento (CE) n. 1987/2006 e dell’articolo 46, paragrafo 8, della decisione 2007/533/GAI, e dell’elenco degli uffici dei sistemi nazionali del SIS II (N.SIS II) e degli uffici SIRENE di cui, rispettivamente, all’articolo 7, paragrafo 3, del regolamento (CE) n. 1987/2006 e all’articolo 7, paragrafo 3, della decisione 2007/533/GAI;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">z)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvede alla pubblicazione annuale dell’elenco delle autorità designate conformemente all’articolo 15, paragrafo 2, del regolamento (CE) n. 2725/2000;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">aa)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">svolge ogni altro compito conferitogli conformemente al presente regolamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione può consigliare il direttore esecutivo su qualsiasi questione strettamente legata allo sviluppo o alla gestione operativa di sistemi IT su larga scala.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Composizione del consiglio di amministrazione", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione è composto di un rappresentante di ciascuno Stato membro e di due rappresentanti della Commissione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni Stato membro e la Commissione nominano i membri del consiglio di amministrazione e i membri supplenti entro il 22 gennaio 2012. Allo scadere di tale periodo la Commissione convoca il consiglio di amministrazione. In caso di assenza i membri sono rappresentati dai loro supplenti.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I membri del consiglio di amministrazione sono nominati in base all’alto livello della loro pertinente esperienza e competenza in materia di sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia e alle loro conoscenze in materia di protezione di dati.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il mandato dei membri è di quattro anni. È rinnovabile una volta. Alla scadenza del loro mandato o in caso di dimissioni i membri restano in carica fino all’eventuale rinnovo del loro mandato o alla loro sostituzione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure Eurodac partecipano alle attività dell’agenzia. Ciascuno di essi nomina un rappresentante e un supplente nel consiglio di amministrazione.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Presidenza del consiglio di amministrazione", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione elegge un presidente e un vicepresidente scegliendoli tra i suoi membri.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il mandato del presidente e del vicepresidente è di due anni. Il loro mandato è rinnovabile una volta. Tuttavia, qualora la loro appartenenza al consiglio di amministrazione termini in un qualsiasi momento durante il loro mandato, questo scade automaticamente alla stessa data.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il presidente e il vicepresidente sono eletti soltanto fra i membri del consiglio di amministrazione nominati dagli Stati membri e che sono pienamente vincolati, in base al diritto dell’Unione, dagli strumenti legislativi che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso di tutti i sistemi IT su larga scala gestiti dall’agenzia.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Riunioni del consiglio di amministrazione", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione è convocato su richiesta:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">del suo presidente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">di almeno un terzo dei suoi membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">del direttore esecutivo.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Il consiglio di amministrazione si riunisce in seduta ordinaria almeno una volta ogni sei mesi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo partecipa alle riunioni del consiglio di amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I membri del consiglio di amministrazione possono farsi assistere da esperti che fanno parte dei gruppi consultivi.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Europol e Eurojust possono assistere alle riunioni del consiglio di amministrazione in qualità di osservatori quando sono all’ordine del giorno questioni concernenti il SIS II, in relazione all’applicazione della decisione 2007/533/GAI. Europol può assistere alle riunioni del consiglio di amministrazione in qualità di osservatore anche quando sono all’ordine del giorno questioni concernenti il VIS, in relazione all’applicazione della decisione 2008/633/GAI.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il consiglio di amministrazione può invitare qualsiasi altra persona, il cui parere possa essere rilevante, a presenziare alle riunioni in veste di osservatore.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L’agenzia provvede a dotare il consiglio di amministrazione di una segreteria.</p>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Modalità di voto", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatti salvi il paragrafo 5 del presente articolo, l’articolo 12, paragrafo 1, lettera j), e l’articolo 18, paragrafi 1 e 7, le decisioni del consiglio di amministrazione sono adottate a maggioranza di tutti i suoi membri aventi diritto di voto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatto salvo il paragrafo 3, ogni membro del consiglio di amministrazione dispone di un voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ogni membro nominato da uno Stato membro che sia vincolato, in base al diritto dell’Unione, da strumenti legislativi che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso di un sistema IT su larga scala gestito dall’agenzia può esprimere il proprio voto su questioni riguardanti quel sistema.</p>\n<p class=\"oj-normal\">Inoltre, per quanto concerne la Danimarca, essa può esprimere il proprio voto su questioni riguardanti tale sistema IT su larga scala qualora decida, ai sensi dell’articolo 4 del protocollo sulla posizione della Danimarca, di recepire lo strumento legislativo che disciplina lo sviluppo, l’istituzione, l’esercizio e l’uso di detto sistema IT su larga scala nel proprio diritto interno.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Per quanto riguarda i paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac, si applica l’articolo 37.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   In caso di disaccordo tra i membri sulla questione se una votazione riguardi o meno uno specifico sistema IT su larga scala, qualsiasi decisione che stabilisca che non lo riguarda è adottata a maggioranza dei due terzi.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il direttore esecutivo non partecipa al voto.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il regolamento interno dell’agenzia stabilisce modalità di votazione più particolareggiate, in particolare le condizioni cui è sottoposto un membro che agisce per conto di un altro e i requisiti di quorum, ove opportuno.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Funzioni e poteri del direttore esecutivo", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’agenzia è gestita e rappresentata dal direttore esecutivo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo è indipendente nell’espletamento delle sue funzioni. Fatte salve le rispettive competenze della Commissione e del consiglio di amministrazione, il direttore esecutivo non sollecita né accetta istruzioni da alcun governo o altro organismo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatto salvo l’articolo 12, il direttore esecutivo si assume la completa responsabilità dei compiti affidati all’agenzia ed è soggetto alla procedura di discarico annuale del Parlamento europeo per l’esecuzione del bilancio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il Parlamento europeo o il Consiglio possono invitare il direttore esecutivo a presentare una relazione sull’esercizio dei propri compiti.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">si occupa della gestione corrente dell’agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantisce il funzionamento dell’agenzia conformemente al presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prepara e applica le procedure, le decisioni e le strategie, i programmi e le attività adottate dal consiglio di amministrazione, nei limiti previsti dal presente regolamento, dalle relative modalità di attuazione e dalla normativa applicabile;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">definisce ed attua un sistema efficace di valutazione e controllo periodico:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dei sistemi IT su larga scala, comprese le statistiche; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dell’agenzia, ivi inclusa la realizzazione efficiente ed efficace dei suoi obiettivi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">partecipa, senza diritto di voto, alle riunioni del consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esercita nei confronti del personale dell’agenzia i poteri di cui all’articolo 20, paragrafo 3, e gestisce le questioni relative al personale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fatto salvo l’articolo 17 dello statuto dei funzionari, stabilisce le clausole di riservatezza per conformarsi, rispettivamente, all’articolo 17 del regolamento (CE) n. 1987/2006, all’articolo 17 della decisione 2007/533/GAI, all’articolo 26, paragrafo 9, del regolamento (CE) n. 767/2008 e per applicare norme adeguate in materia di segreto professionale o altri obblighi di riservatezza equivalenti al personale dell’agenzia che deve lavorare con i dati Eurodac;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">negozia e, una volta approvato dal consiglio di amministrazione, firma l’accordo relativo alla sede dell’agenzia e gli accordi relativi ai siti tecnici e di riserva con il governo degli Stati membri ospitanti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il direttore esecutivo sottopone al consiglio di amministrazione, per adozione, in particolare i progetti dei seguenti atti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">programma di lavoro annuale dell’agenzia e relativa relazione annuale di attività, previa consultazione dei gruppi consultivi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">norme finanziarie applicabili all’agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">programma di lavoro pluriennale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">bilancio per l’esercizio successivo, elaborato in base al sistema della formazione del bilancio per attività;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">piano strategico pluriennale per il personale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">mandato per la valutazione di cui all’articolo 31;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">modalità pratiche di applicazione del regolamento (CE) n. 1049/2001;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">misure di sicurezza necessarie, compresi un piano di sicurezza ed un piano di continuità operativa e di ripristino in caso di disastro;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">relazioni sul funzionamento tecnico di ogni sistema IT su larga scala di cui all’articolo 12, paragrafo 1, lettera t), e di relazione annuale sulle attività del sistema centrale di Eurodac di cui all’articolo 12, paragrafo 1, lettera u), sulla base dei risultati del controllo e della valutazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">elenco annuale, a fini di pubblicazione, delle autorità competenti autorizzate a consultare direttamente i dati inseriti nel SIS II, compreso l’elenco degli uffici N.SIS II e degli uffici SIRENE, di cui all’articolo 12, paragrafo 1, lettera y), e l’elenco delle autorità di cui all’articolo 12, paragrafo 1, lettera z).</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il direttore esecutivo svolge ogni altro compito conformemente al presente regolamento.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Nomina del direttore esecutivo", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione nomina il direttore esecutivo per un periodo di cinque anni da un elenco di candidati ammissibili selezionati tramite un concorso generale organizzato dalla Commissione. La procedura di selezione prevede la pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span> e in altri strumenti d’informazione di un invito a manifestare interesse. Il consiglio di amministrazione può richiedere l’organizzazione di una nuova procedura se non è persuaso dell’idoneità di nessuno dei candidati inclusi nell’elenco. Il consiglio di amministrazione nomina il direttore esecutivo sulla base dei suoi meriti personali, alla sua esperienza in materia di sistemi IT su larga scala e alle sue capacità amministrative, finanziarie e di gestione ed alle sue conoscenze in materia di protezione di dati. Il consiglio di amministrazione adotta la sua decisione di nomina del direttore esecutivo a maggioranza di due terzi di tutti i suoi membri aventi diritto di voto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Prima della nomina, il candidato prescelto dal consiglio di amministrazione è invitato a rendere una dichiarazione dinanzi alla o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri delle commissioni. Dopo detta dichiarazione il Parlamento europeo adotta un parere nel quale espone la sua opinione sul candidato selezionato. Il consiglio di amministrazione informa il Parlamento europeo del modo in cui tale parere è stato preso in considerazione. Il parere è trattato in modo personale e riservato fino alla nomina del candidato.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nei nove mesi che precedono la fine del mandato di cinque anni, il consiglio di amministrazione, in stretta consultazione con la Commissione, procede a una valutazione nel cui ambito esamina, in particolare, i risultati ottenuti durante il primo mandato del direttore esecutivo e il modo in cui sono stati conseguiti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio d’amministrazione, tenuto conto della relazione di valutazione e solo quando gli obiettivi e i compiti dell’agenzia lo giustificano, può prorogare una volta il mandato del direttore esecutivo per un massimo di tre anni.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il consiglio di amministrazione informa il Parlamento europeo dell’intenzione di prorogare il mandato del direttore esecutivo. Nel mese precedente tale proroga, il direttore esecutivo è invitato a rendere una dichiarazione dinanzi alla o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri delle commissioni.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il direttore esecutivo risponde al consiglio di amministrazione.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il consiglio di amministrazione può revocare il direttore esecutivo. Il consiglio di amministrazione adotta tale decisione a maggioranza di due terzi di tutti i suoi membri aventi diritto di voto.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Gruppi consultivi", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I seguenti gruppi consultivi forniscono al consiglio di amministrazione le competenze tecniche relative ai sistemi IT su larga scala, in particolare nel contesto della preparazione del programma di lavoro annuale e della relazione annuale di attività:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gruppo consultivo SIS II;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gruppo consultivo VIS;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gruppo consultivo Eurodac;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ogni altro gruppo consultivo relativo a un sistema IT su larga scala, se così previsto dal pertinente strumento legislativo che disciplina lo sviluppo, l’istituzione, l’esercizio e l’uso di tale sistema IT su larga scala.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni Stato membro che sia vincolato, in base al diritto dell’Unione, da strumenti legislativi che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso di un sistema IT su larga scala, e la Commissione nominano un membro in seno al gruppo consultivo relativo al sistema IT su larga scala in questione con un mandato di tre anni, rinnovabile.</p>\n<p class=\"oj-normal\">Per quanto riguarda la Danimarca, essa nomina parimenti un membro in seno al gruppo consultivo relativo ad un sistema IT su larga scala qualora decida, ai sensi dell’articolo 4 del protocollo sulla posizione della Danimarca, di recepire lo strumento legislativo che disciplina lo sviluppo, l’istituzione, l’esercizio e l’uso di quello specifico sistema IT su larga scala nel proprio diritto interno.</p>\n<p class=\"oj-normal\">Ciascun paese associato all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen, alle misure relative a Eurodac e alle misure relative ad altri sistemi IT su larga scala che partecipa a un determinato sistema IT su larga scala nomina un membro in seno al gruppo consultivo relativo al sistema IT su larga scala in questione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Sia Europol che Eurojust può nominare un rappresentante in seno al gruppo consultivo SIS II. Europol può nominare anche un rappresentante in seno al gruppo consultivo VIS.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I membri del consiglio di amministrazione non sono membri di nessun gruppo consultivo. Il direttore esecutivo o il rappresentante del direttore esecutivo può presenziare a tutte le riunioni dei gruppi consultivi in qualità di osservatori.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le procedure per il funzionamento e la cooperazione dei gruppi consultivi sono specificate nel regolamento interno dell’agenzia.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Quando preparano un parere, i membri di ogni gruppo consultivo si adoperano per giungere ad un consenso. Se tale consenso non è raggiunto, il parere rispecchia la posizione motivata della maggioranza dei membri. È messa a verbale anche la posizione o le posizioni di minoranza motivate. L’articolo 16, paragrafi 3 e 4, si applica di conseguenza. I membri che rappresentano i paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac possono esprimere pareri sulle questioni sulle quali non hanno diritto di voto.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Ciascuno Stato membro e ciascun paese associato all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac facilita le attività dei gruppi consultivi.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L’articolo 14 si applica alla presidenza dei gruppi consultivi, mutatis mutandis.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Personale", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al personale dell’agenzia e al direttore esecutivo si applicano lo statuto dei funzionari e le norme adottate congiuntamente dalle istituzioni dell’Unione per l’applicazione dello stesso.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ai fini dell’attuazione dello statuto, l’agenzia è considerata un’agenzia ai sensi dell’articolo 1 <span class=\"oj-italic\">bis</span>, paragrafo 2, dello statuto dei funzionari.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nei confronti del proprio personale, l’agenzia esercita i poteri conferiti all’autorità investita del potere di nomina dallo statuto dei funzionari e all’autorità abilitata a stipulare contratti dal regime applicabile agli altri agenti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il personale dell’agenzia è composto di funzionari e agenti temporanei o contrattuali. Il consiglio di amministrazione dà il proprio assenso su base annuale qualora i contratti che il direttore esecutivo intende rinnovare diventino contratti a tempo indeterminato in base al regime applicabile agli altri agenti.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L’agenzia non assume personale interinale per svolgere mansioni finanziarie considerate sensibili.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   La Commissione e gli Stati membri possono distaccare temporaneamente funzionari o esperti nazionali presso l’agenzia. Il consiglio di amministrazione, tenuto conto del piano pluriennale in materia di politica del personale, adotta le misure di attuazione necessarie a tal fine.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Fatto salvo l’articolo 17 dello statuto dei funzionari, l’agenzia applica norme adeguate in materia di segreto professionale o altri obblighi di riservatezza equivalenti.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il consiglio di amministrazione, di concerto con la Commissione, adotta le necessarie disposizioni di esecuzione secondo le modalità di cui all’articolo 110 dello statuto dei funzionari.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Interesse pubblico", "anchor": "art_21", "frags": [[null, "<p class=\"oj-normal\">I membri del consiglio di amministrazione, il direttore esecutivo e i membri dei gruppi consultivi si impegnano ad agire nell’interesse pubblico. A tal fine, essi emettono una dichiarazione scritta d’impegno annuale e pubblica.</p>"], [null, "<p class=\"oj-normal\">L’elenco dei membri del consiglio di amministrazione è pubblicato nel sito Internet dell’agenzia.</p>"]]}, "22": {"label": "Articolo 22", "heading": "Accordo relativo alla sede e accordi relativi ai siti tecnici e di riserva", "anchor": "art_22", "frags": [[null, "<p class=\"oj-normal\">Le necessarie disposizioni relative all’insediamento dell’agenzia negli Stati membri ospitanti e alle strutture che tali Stati membri devono mettere a disposizione, e le norme specifiche applicabili negli Stati membri ospitanti al direttore esecutivo, ai membri del consiglio d’amministrazione, al personale dell’agenzia e ai familiari, sono fissate in un accordo sulla sede dell’agenzia e in accordi sui siti tecnici e di riserva conclusi fra l’agenzia e gli Stati membri ospitanti, previa approvazione del consiglio d’amministrazione.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Privilegi e immunità", "anchor": "art_23", "frags": [[null, "<p class=\"oj-normal\">All’agenzia si applica il protocollo sui privilegi e sulle immunità dell’Unione europea.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Responsabilità", "anchor": "art_24", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La responsabilità contrattuale dell’agenzia è disciplinata dalla normativa applicabile al contratto di cui trattasi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Corte di giustizia dell’Unione europea è competente a giudicare in virtù di clausole compromissorie contenute in un contratto concluso dall’agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In materia di responsabilità extracontrattuale l’agenzia risarcisce, secondo i principi generali comuni agli ordinamenti degli Stati membri, i danni causati dai suoi servizi o dai suoi agenti nell’esercizio delle loro funzioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Corte di giustizia dell’Unione europea è competente a pronunciarsi in merito alle controversie relative al risarcimento dei danni di cui al paragrafo 3.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La responsabilità personale del personale dell’agenzia verso l’agenzia è disciplinata dalle disposizioni dello statuto.</p>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Regime linguistico", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   All’agenzia si applica il regolamento n. 1, del 15 aprile 1958, che stabilisce il regime linguistico della Comunità economica europea (<span class=\"oj-super oj-note-tag\">30</span>).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatte salve le decisioni adottate in base all’articolo 342 TFUE, il programma di lavoro annuale e la relazione annuale di attività di cui all’articolo 12, paragrafo 1, lettere j) e k), sono redatti in tutte le lingue ufficiali delle istituzioni dell’Unione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I servizi di traduzione necessari per il funzionamento dell’agenzia sono forniti dal Centro di traduzione degli organismi dell’Unione europea.</p>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Accesso ai documenti", "anchor": "art_26", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   In base ad una proposta del direttore esecutivo ed entro sei mesi dal 1<span class=\"oj-super\">o</span> dicembre 2012, il consiglio di amministrazione adotta le norme relative all’accesso ai documenti dell’agenzia conformemente al regolamento (CE) n. 1049/2001.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le decisioni adottate dall’agenzia ai sensi dell’articolo 8 del regolamento (CE) n. 1049/2001 possono costituire oggetto di denuncia presso il Mediatore europeo o di ricorso dinanzi alla Corte di giustizia dell’Unione europea alle condizioni, rispettivamente, di cui agli articoli 228 e 263 TFUE.</p>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Informazione e comunicazione", "anchor": "art_27", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’agenzia effettua comunicazioni nei settori che rientrano nelle sue funzioni conformemente agli strumenti legislativi che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso dei sistemi IT su larga scala e di propria iniziativa. Essa assicura, in particolare, che oltre alla pubblicazione specificata all’articolo 12, paragrafo 1, lettere j), k), w) e y), e all’articolo 33, paragrafo 8, il pubblico e qualsiasi altra parte interessata ricevano prontamente informazioni obiettive, affidabili e di facile comprensione relative alla sua attività.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione stabilisce le modalità pratiche per l’applicazione del paragrafo 1.</p>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Protezione dei dati", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatte salve le disposizioni sulla protezione dei dati stabilite dagli strumenti legislativi che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso dei sistemi IT su larga scala, le informazioni trattate dall’agenzia conformemente al presente regolamento sono soggette al regolamento (CE) n. 45/2001.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione stabilisce le modalità di applicazione del regolamento (CE) n. 45/2001 da parte dell’agenzia e in particolare della sezione 8, relativa al responsabile della protezione dei dati.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Norme di sicurezza in materia di protezione delle informazioni classificate e delle informazioni sensibili non classificate", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’agenzia applica i principi in materia di sicurezza stabiliti dalla decisione 2001/844/CE, CECA, Euratom della Commissione, del 29 novembre 2001, che modifica il regolamento interno della Commissione (<span class=\"oj-super oj-note-tag\">31</span>), ivi incluse le disposizioni relative allo scambio, al trattamento e all’archiviazione delle informazioni classificate e le misure relative alla sicurezza materiale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’agenzia applica altresì i principi di sicurezza relativi al trattamento delle informazioni sensibili non classificate adottati e applicati dalla Commissione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio di amministrazione decide, conformemente all’articolo 2 e all’articolo 12, paragrafo 1, lettera p), la struttura interna dell’agenzia necessaria ai fini dell’applicazione degli appropriati principi di sicurezza.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Sicurezza dell’agenzia", "anchor": "art_30", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’agenzia è responsabile della sicurezza e del mantenimento dell’ordine negli edifici, nei locali e sui terreni da essa utilizzati. L’agenzia applica i principi di sicurezza e le pertinenti disposizioni degli strumenti legislativi che disciplinano lo sviluppo, l’istituzione, l’esercizio e l’uso dei sistemi IT su larga scala.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri ospitanti prendono tutte le misure efficaci e adeguate per mantenere l’ordine e la sicurezza nelle immediate vicinanze degli edifici, dei locali e dei terreni utilizzati dall’agenzia e forniscono a quest’ultima una protezione adeguata conformemente all’accordo relativo alla sede dell’agenzia e agli accordi relativi ai siti tecnici e di riserva pertinenti, garantendo nel contempo il libero accesso a tali edifici, locali e terreni alle persone autorizzate dall’agenzia.</p>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Valutazione", "anchor": "art_31", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro tre anni dal 1<span class=\"oj-super\">o</span> dicembre 2012, e successivamente ogni quattro anni, la Commissione, in stretta consultazione con il consiglio di amministrazione, effettua una valutazione dell’operato dell’agenzia. La valutazione esamina come e in che misura l’agenzia contribuisca effettivamente alla gestione operativa dei sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia e adempia ai compiti stabiliti dal presente regolamento. La valutazione esamina altresì il ruolo dell’agenzia nel contesto di una strategia dell’Unione intesa a stabilire a livello di Unione un ambiente IT coordinato, efficiente in termini di costi e coerente da realizzare nei prossimi anni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Sulla base della valutazione di cui al paragrafo 1, la Commissione, previa consultazione del consiglio di amministrazione, formula raccomandazioni sulle modifiche da apportare al presente regolamento, anche per renderlo maggiormente conforme alla strategia dell’Unione di cui al paragrafo 1. La Commissione trasmette tali raccomandazioni, insieme al parere del consiglio di amministrazione e ad opportune proposte, al Parlamento europeo, al Consiglio e al garante europeo della protezione dei dati.</p>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Bilancio", "anchor": "art_32", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatti salvi altri tipi di risorse, le entrate dell’agenzia comprendono:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dell’Unione iscritto nel bilancio generale dell’Unione europea (sezione Commissione);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dei paesi terzi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contributi finanziari degli Stati membri.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le spese dell’agenzia comprendono, tra l’altro, le retribuzioni del personale, le spese amministrative e di infrastruttura, le spese di esercizio e le spese attinenti a contratti o accordi conclusi dall’agenzia. Ogni anno il direttore esecutivo prepara, tenendo conto delle attività svolte dall’agenzia, un progetto di stato di previsione delle entrate e delle spese dell’agenzia per l’esercizio successivo, unitamente alla tabella dell’organico, e lo trasmette al consiglio di amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le entrate e le spese dell’agenzia devono risultare in pareggio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio di amministrazione, sulla base del progetto stabilito dal direttore esecutivo, adotta il progetto di stato di previsione delle entrate e delle spese dell’agenzia per l’esercizio successivo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il consiglio di amministrazione trasmette alla Commissione e ai paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac il progetto di stato di previsione delle spese e delle entrate dell’agenzia e gli orientamenti generali che le giustificano entro il 10 febbraio di ogni anno e il progetto definitivo dello stato di previsione entro il 31 marzo di ogni anno.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Entro il 31 marzo di ogni anno il consiglio di amministrazione presenta alla Commissione e all’autorità di bilancio:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il suo progetto di programma di lavoro annuale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il suo piano pluriennale aggiornato in materia di politica del personale, elaborato conformemente agli orientamenti stabiliti dalla Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le informazioni sul numero di funzionari, agenti temporanei e contrattuali definiti nello statuto per gli anni n-1 e n, nonché una stima per l’anno n+1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni sui contributi in natura concessi all’agenzia dagli Stati membri ospitanti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una stima del saldo del risultato dell’esecuzione del bilancio per l’anno n-1.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Lo stato di previsione è trasmesso dalla Commissione all’autorità di bilancio unitamente al progetto di bilancio generale dell’Unione europea.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Sulla base dello stato di previsione, la Commissione inserisce nel progetto di bilancio generale dell’Unione europea le previsioni ritenute necessarie per la tabella dell’organico nonché l’importo della sovvenzione da iscrivere nel bilancio generale che trasmette all’autorità di bilancio a norma dell’articolo 314 TFUE.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   L’autorità di bilancio autorizza gli stanziamenti a titolo della sovvenzione destinata all’agenzia. L’autorità di bilancio adotta la tabella dell’organico per l’agenzia.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Il consiglio di amministrazione adotta il bilancio dell’agenzia. Esso diventa definitivo dopo l’adozione definitiva del bilancio generale dell’Unione europea. Se del caso, si procede agli opportuni adeguamenti.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Qualsiasi modifica del bilancio, ivi inclusa la tabella dell’organico, segue la medesima procedura.</p>\n</div>"], [12, "<div>\n<p class=\"oj-normal\">12.   Il consiglio d’amministrazione comunica al più presto all’autorità di bilancio l’intenzione di realizzare qualsiasi progetto che può avere incidenze finanziarie significative per il finanziamento del bilancio, in particolare i progetti di natura immobiliare, quali l’affitto o l’acquisto di edifici. Esso ne informa la Commissione e i paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac. Qualora uno dei due rami dell’autorità di bilancio intenda formulare un parere, esso notifica al consiglio di amministrazione, entro due settimane dal ricevimento dell’informazione relativa al progetto, che intende formulare detto parere. In mancanza di risposta, l’agenzia può procedere con l’operazione prevista.</p>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Esecuzione del bilancio", "anchor": "art_33", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo è responsabile dell’esecuzione del bilancio dell’agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo trasmette ogni anno all’autorità di bilancio qualsiasi informazione utile riguardante i risultati delle procedure di valutazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Entro il 1<span class=\"oj-super\">o</span> marzo che segue l’esercizio chiuso, il contabile dell’agenzia comunica al contabile della Commissione e alla Corte dei conti i conti provvisori dell’agenzia corredati della relazione sulla gestione finanziaria e di bilancio dell’esercizio. Il contabile della Commissione consolida i conti provvisori delle istituzioni e degli organismi decentrati ai sensi dell’articolo 128 del regolamento (CE, Euratom) n. 1605/2002.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Entro il 31 marzo che segue l’esercizio chiuso, il contabile dell’agenzia trasmette la relazione sulla gestione finanziaria e di bilancio anche all’autorità di bilancio.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Al ricevimento delle osservazioni della Corte dei conti sui conti provvisori dell’agenzia, ai sensi dell’articolo 129 del regolamento (CE, Euratom) n. 1605/2002, il direttore esecutivo stabilisce i conti definitivi dell’agenzia sotto la propria responsabilità e li trasmette al consiglio di amministrazione per parere.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio d’amministrazione formula un parere sui conti definitivi dell’agenzia.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Entro il 1<span class=\"oj-super\">o</span> luglio che segue l’esercizio chiuso, il direttore esecutivo trasmette i conti definitivi, corredati del parere del consiglio di amministrazione, all’autorità di bilancio, al contabile della Commissione, alla Corte dei conti, nonché ai paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   I conti definitivi sono pubblicati.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Il direttore esecutivo invia alla Corte dei conti una risposta alle sue osservazioni entro il 30 settembre. Il direttore esecutivo trasmette tale risposta anche al Consiglio di amministrazione.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Su richiesta del Parlamento europeo, il direttore esecutivo presenta le informazioni necessarie al corretto svolgimento della procedura di discarico per l’esercizio in causa, secondo quanto previsto dall’articolo 146, paragrafo 3, del regolamento (CE, Euratom) n. 1605/2002.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Il Parlamento europeo, su raccomandazione del Consiglio che delibera a maggioranza qualificata, concede il discarico al direttore esecutivo, entro il 15 maggio dell’anno n+2, relativamente all’esecuzione del bilancio dell’esercizio n.</p>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Norme finanziarie", "anchor": "art_34", "frags": [[null, "<p class=\"oj-normal\">Le norme finanziarie applicabili all’agenzia sono adottate dal consiglio di amministrazione, previa consultazione della Commissione. Esse si discostano dal regolamento (CE, Euratom) n. 2343/2002 solo per esigenze specifiche di funzionamento dell’agenzia e previo accordo della Commissione.</p>"]]}, "35": {"label": "Articolo 35", "heading": "Lotta antifrode", "anchor": "art_35", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ai fini della lotta contro la frode, la corruzione ed altri atti illeciti si applica il regolamento (CE) n. 1073/1999.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’agenzia aderisce all’accordo interistituzionale relativo alle indagini interne svolte dall’Ufficio europeo per la lotta antifrode (OLAF) e adotta immediatamente le opportune disposizioni, applicabili a tutto il personale dell’agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le decisioni concernenti il finanziamento e i correlati accordi e strumenti di attuazione stabiliscono espressamente che la Corte dei conti e l’OLAF possono svolgere, se necessario, controlli in loco presso i beneficiari dei finanziamenti dell’agenzia e gli agenti responsabili della loro assegnazione.</p>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Azioni preparatorie", "anchor": "art_36", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione è responsabile dell’istituzione e del funzionamento iniziale dell’agenzia finché questa non abbia la capacità operativa di eseguire il proprio bilancio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   A tal fine, fino a quando il direttore esecutivo non assume le proprie funzioni dopo la nomina da parte del consiglio di amministrazione conformemente all’articolo 18, la Commissione può distaccare ad interim un numero limitato di suoi funzionari, compreso uno che svolga le funzioni di direttore esecutivo. Il direttore esecutivo ad interim può essere designato solo una volta convocato il consiglio di amministrazione, a norma dell’articolo 13, paragrafo 2.</p>\n<p class=\"oj-normal\">Se il direttore esecutivo ad interim non assolve agli obblighi stabiliti dal presente regolamento, il consiglio di amministrazione può chiedere alla Commissione di designare un nuovo direttore esecutivo ad interim.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo ad interim può autorizzare tutti i pagamenti coperti dagli stanziamenti previsti nel bilancio dell’agenzia, previa approvazione del consiglio di amministrazione, e può concludere contratti, anche relativi al personale, in seguito all’adozione della tabella dell’organico dell’agenzia. Se giustificato, il consiglio di amministrazione può imporre restrizioni ai poteri del direttore esecutivo ad interim.</p>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Partecipazione dei paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac", "anchor": "art_37", "frags": [[null, "<p class=\"oj-normal\">Conformemente alle pertinenti disposizioni dei rispettivi accordi di associazione, sono presi accordi per specificare in particolare la natura, la portata e le modalità di partecipazione ai lavori dell’agenzia dei paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen e alle misure relative a Eurodac, comprese disposizioni sui contributi finanziari, sul personale e sul diritto di voto.</p>"]]}, "38": {"label": "Articolo 38", "heading": "Entrata in vigore e applicazione", "anchor": "art_38", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"oj-normal\">L’agenzia assume le responsabilità ad essa conferite agli articoli da 3 a 9 a decorrere dal 1<span class=\"oj-super\">o</span> dicembre 2012.</p>"]]}}, "recitals": {}};